# LeoWiki-MCP  –  Split Screen: Glass Logo + Live Log Panel
# Usage:  python your_script.py | pwsh LeoWiki-Logo.ps1
[console]::OutputEncoding = [System.Text.Encoding]::UTF8
[console]::CursorVisible  = $false

$esc    = [char]27
$RST    = "$esc[0m"
$BBLK   = "$esc[40m"

# ── LAYOUT (adapts to actual terminal size) ───────────────────────────────────
$_ws    = $Host.UI.RawUI.WindowSize
$TW     = $_ws.Width
$TH     = $_ws.Height
$BUF_H  = $TH - 1

$ART_W  = 44
$ART_H  = 44
$ART_COL = 2
$ART_ROW = [Math]::Max(1, [int](($BUF_H - $ART_H) / 2))

$DIV_COL   = $ART_COL + $ART_W + 2          # divider column
$PANEL_COL = $DIV_COL + 2                    # panel text start
$PANEL_W   = $TW - 52                        # ART_COL(2)+ART_W(44)+gap(2)+║+sp+…+sp+║ = 52+PANEL_W
$PANEL_ROWS = $ART_H - 4                     # text rows in panel (matches logo height)
$PANEL_TOP  = $ART_ROW + 2                   # first text row (below panel header)

# ── COLORS ────────────────────────────────────────────────────────────────────
$CB  = "$esc[38;2;60;90;130m"      # border blue-gray
$CT  = "$esc[1;38;2;110;165;215m"  # title bright blue
$CTS = "$esc[38;2;70;75;90m"       # timestamp dim
$CTX = "$esc[38;2;195;210;225m"    # normal text
$CW  = "$esc[38;2;215;155;55m"     # warn  orange
$CE  = "$esc[38;2;215;75;75m"      # error red
$COK = "$esc[38;2;75;195;115m"     # ok    green
$CD  = "$esc[38;2;45;55;65m"       # dim / empty rows


