# ── STDIN → CONCURRENT QUEUE (background thread) ─────────────────────────────
# ── PROCESS OUTPUT QUEUE ─────────────────────────────────────────────────────
if (-not ('ProcQ' -as [type])) {
Add-Type -TypeDefinition @"
using System;
using System.Collections.Concurrent;
using System.Diagnostics;
using System.Threading;

public static class ProcQ {
    public static readonly ConcurrentQueue<string> Lines
        = new ConcurrentQueue<string>();
    public static volatile bool Running = false;
    public static volatile int  ExitCode = 0;
    private static Process _proc = null;

    public static void Drain() {
        string s;
        while (Lines.TryDequeue(out s)) {}
    }

    public static void StartProcess(string fileName, string arguments, string workDir) {
        Drain();
        Running  = true;
        ExitCode = 0;
        _proc    = null;
        var psi = new ProcessStartInfo {
            FileName               = fileName,
            Arguments              = arguments,
            WorkingDirectory       = workDir,
            RedirectStandardOutput = true,
            RedirectStandardError  = true,
            UseShellExecute        = false,
            CreateNoWindow         = true
        };
        var p = new Process { StartInfo = psi };
        _proc = p;
        p.Start();
        new Thread(() => {
            try { string ln; while ((ln = p.StandardOutput.ReadLine()) != null) Lines.Enqueue(ln); }
            catch {}
            try { p.WaitForExit(); } catch {}
            try { ExitCode = p.HasExited ? p.ExitCode : 1; } catch { ExitCode = 1; }
            Running = false;
        }) { IsBackground = true }.Start();
        new Thread(() => {
            try { string ln; while ((ln = p.StandardError.ReadLine()) != null) Lines.Enqueue(ln); }
            catch {}
        }) { IsBackground = true }.Start();
    }

    public static void Kill() {
        var p = _proc;
        try { if (p != null && !p.HasExited) p.Kill(); } catch {}
        ExitCode = -1;
        Running = false;
    }
}
"@
}

# ── MENU ITEMS + STATE ────────────────────────────────────────────────────────
$DD_ROOT = if ($PSScriptRoot) { Split-Path $PSScriptRoot -Parent } `
           else { Split-Path (Split-Path $MyInvocation.MyCommand.Path) -Parent }
$_py   = if (Get-Command python -EA 0) { (Get-Command python).Source } else { 'python' }
$_pwsh = if (Get-Command pwsh   -EA 0) { (Get-Command pwsh).Source   } else { 'pwsh'   }

# Capture Write-Host from multiscript via 6>&1 inside the child pwsh process.
# -OutputFormat Text  → prevents PowerShell from wrapping output in CLIXML when
#                       stdout is redirected (non-TTY).  Without it you get the
#                       <Objs Version="1.1.0.1"...> XML garbage in the log panel.
# $PSStyle.OutputRendering='ANSI' → keeps ANSI colour codes even in a pipe.
$_msPath = "$DD_ROOT\scripts\_JANS_MULTISCRIPT_.ps1"
$_msCmd  = "`$PSStyle.OutputRendering='ANSI'; & '$_msPath' 6>&1"
$_msEnc  = [Convert]::ToBase64String([Text.Encoding]::Unicode.GetBytes($_msCmd))

# Python -u  → forces unbuffered stdout/stderr so lines appear immediately
#              instead of arriving all at once when the script exits.
#              This does NOT modify the Python scripts themselves.

# ── LM STUDIO AUTO-START ──────────────────────────────────────────────────────
# Steps 2 & 3 require LM Studio to be running with the correct model loaded.
# New-LmsArg builds a pwsh -EncodedCommand wrapper that:
#   1. Checks if LM Studio server is up  (GET /v1/models or /api/v1/models → 200/401)
#   2. If offline  → launches LM Studio app / lms server start  (then polls until ready)
#   3. If model not loaded → runs: lms load <model>  (polls /api/v1/models loaded_instances)
#   4. Finally runs the Python pipeline script via python -u
# All output (Write-Host + stdout + stderr) is captured by ProcQ via 6>&1.
# Note: OpenAI /v1/models often returns {"data":[]} even when models exist; native
# /api/v1/models is authoritative for catalog + load state (key / loaded_instances).
$_lmsUrl   = 'http://127.0.0.1:1234/v1'
$_lmsModel = 'qwen/qwen2.5-vl-7b'

function New-LmsArg ([string]$lmsUrl, [string]$lmsModel, [string]$pyExe, [string]$pyScript) {
    # Build the inner command as a here-string, then Base64-encode it for
    # pwsh -EncodedCommand.  Escaping rules inside @"..."@:
    #   `$var  →  literal $var  (evaluated at runtime in child pwsh)
    #    $var  →  expanded NOW  (baked-in value from outer pwsh - used for
    #             $lmsUrl/$lmsModel/$pyExe/$pyScript which are function params)
    $inner = @"
`$PSStyle.OutputRendering = 'ANSI'
`$lmsUrl   = '$lmsUrl'
`$lmsModel = '$lmsModel'
`$lmsBase  = (`$lmsUrl -replace '/v1/?$','').TrimEnd('/')
`$lmsPort  = 1234
if (`$lmsUrl -match ':(\d+)') { `$lmsPort = [int]`$Matches[1] }

function Get-LmsHeaders {
    `$h = @{}
    `$tok = `$env:LM_API_TOKEN
    if (-not `$tok) { `$tok = `$env:LMS_API_TOKEN }
    if (`$tok) { `$h['Authorization'] = "Bearer `$tok" }
    return `$h
}
function Test-LmsHttpReady ([string]`$url) {
    # Any reachable LMS HTTP response means the server is up.
    # 200 = usable; 401 = auth required but listening (do NOT treat as offline).
    try {
        `$r = Invoke-WebRequest -Uri `$url -Headers (Get-LmsHeaders) -TimeoutSec 5 -SkipHttpErrorCheck
        `$code = [int]`$r.StatusCode
        if (`$code -eq 200 -or `$code -eq 401) { return `$true }
    } catch {}
    return `$false
}
function Test-LmsServer {
    if (Test-LmsHttpReady "`$lmsUrl/models") { return `$true }
    if (Test-LmsHttpReady "`$lmsBase/api/v1/models") { return `$true }
    # TCP fallback: port open => app/server process is accepting connections
    try {
        `$client = [System.Net.Sockets.TcpClient]::new()
        `$iar = `$client.BeginConnect('127.0.0.1', `$lmsPort, `$null, `$null)
        `$ok = `$iar.AsyncWaitHandle.WaitOne(1500, `$false)
        if (`$ok -and `$client.Connected) { `$client.Close(); return `$true }
        `$client.Close()
    } catch {}
    return `$false
}
function Test-LmsModel {
    `$hdr = Get-LmsHeaders
    # Prefer native /api/v1/models — OpenAI /v1/models often returns empty data:[]
    # even when the catalog has dozens of models. Shape: { models: [{ key, loaded_instances, ... }] }
    try {
        `$r2 = Invoke-WebRequest -Uri "`$lmsBase/api/v1/models" -Headers `$hdr -TimeoutSec 5 -SkipHttpErrorCheck
        if ([int]`$r2.StatusCode -eq 200 -and `$r2.Content) {
            `$j2 = `$r2.Content | ConvertFrom-Json
            `$models = @()
            if (`$j2.models) { `$models = @(`$j2.models) }
            elseif (`$j2.data) { `$models = @(`$j2.data) }
            foreach (`$m in `$models) {
                `$id = if (`$m.key) { [string]`$m.key } elseif (`$m.id) { [string]`$m.id } else { '' }
                if (-not `$id -or `$id -notlike "*`$lmsModel*") { continue }
                # Non-empty loaded_instances => model is in memory and ready
                `$loaded = @(`$m.loaded_instances | Where-Object { `$_ })
                if (`$loaded.Count -gt 0) { return `$true }
            }
        }
    } catch {}
    # Fallback: OpenAI /v1/models only when it actually lists models (ignore empty data:[])
    try {
        `$r = Invoke-WebRequest -Uri "`$lmsUrl/models" -Headers `$hdr -TimeoutSec 5 -SkipHttpErrorCheck
        if ([int]`$r.StatusCode -eq 200 -and `$r.Content -and (`$r.Content -notmatch 'Unexpected endpoint')) {
            `$j = `$r.Content | ConvertFrom-Json
            `$data = @(`$j.data | Where-Object { `$_ })
            if (`$data.Count -gt 0 -and (`$data | Where-Object { `$_.id -like "*`$lmsModel*" }).Count -gt 0) {
                return `$true
            }
        }
    } catch {}
    return `$false
}
function Wait-For ([scriptblock]`$test, [int]`$stepSec, [int]`$maxSec, [string]`$msg) {
    `$waited = 0
    while (-not (& `$test)) {
        if (`$waited -ge `$maxSec) { return `$false }
        Start-Sleep -Seconds `$stepSec
        `$waited += `$stepSec
        Write-Host "`$msg (`${waited}s / `${maxSec}s)"
    }
    return `$true
}

Write-Host "[LMS] Checking LM Studio at `$lmsUrl ..."
if (-not `$env:LM_API_TOKEN -and -not `$env:LMS_API_TOKEN) {
    Write-Host "[WARN] LM_API_TOKEN not set - LMS may return 401 if auth is enabled."
}
if (-not (Test-LmsServer)) {
    # lms server start is a thin CLI wrapper that requires the LM Studio app to
    # already be running.  Launch the full application directly instead.
    `$lmsAppExe = @(
        "`$env:LOCALAPPDATA\Programs\LM Studio\LM Studio.exe",
        "`$env:LOCALAPPDATA\Programs\lm-studio\LM Studio.exe",
        "`$env:LOCALAPPDATA\LM-Studio\LM Studio.exe"
    ) | Where-Object { Test-Path `$_ } | Select-Object -First 1

    if (`$lmsAppExe) {
        Write-Host "[LMS] Launching LM Studio: `$lmsAppExe"
        Start-Process `$lmsAppExe
    } else {
        # Fallback: try the lms CLI via cmd.exe (handles .cmd/.bat on PATH)
        Write-Host "[LMS] App not found in standard paths - trying 'lms server start'..."
        Start-Process 'cmd.exe' -ArgumentList '/c','lms server start' -WindowStyle Hidden
    }

    if (-not (Wait-For { Test-LmsServer } 3 90 '[LMS] Waiting for server...')) {
        Write-Host "[ERROR] LM Studio server did not become available within 90 s."
        Write-Host "[ERROR] Please open LM Studio and enable the API server on port 1234."
        Write-Host "[ERROR] If auth is enabled, set LM_API_TOKEN to your LMS API token."
        exit 1
    }
    Write-Host "[LMS] Server is up."
} else {
    Write-Host "[LMS] Server already reachable."
}
if (-not (Test-LmsModel)) {
    Write-Host "[LMS] Model '`$lmsModel' not loaded - loading via lms CLI ..."
    Start-Process 'cmd.exe' -ArgumentList '/c',"lms load `$lmsModel -y" -WindowStyle Hidden
    if (-not (Wait-For { Test-LmsModel } 3 120 '[LMS] Loading model...')) {
        Write-Host "[ERROR] Model '`$lmsModel' did not load within 120 s."
        Write-Host "[ERROR] Try loading it manually in LM Studio first."
        exit 1
    }
    Write-Host "[LMS] Model '`$lmsModel' ready."
}
Write-Host "[LMS] LM Studio ready - launching pipeline step."
& '$pyExe' -u '$pyScript'
exit `$LASTEXITCODE
"@
    $enc = [Convert]::ToBase64String([Text.Encoding]::Unicode.GetBytes($inner))
    return "-NoProfile -NonInteractive -OutputFormat Text -EncodedCommand $enc"
}

$menuItems = @(
    @{ label = 'Run Full Stack  (Multiscript)';       exe = $_pwsh; arg = "-NoProfile -NonInteractive -OutputFormat Text -EncodedCommand $_msEnc"                                                                      }
    @{ label = 'Step 1  ─  Wiki Fetcher';             exe = $_py;   arg = "-u `"$DD_ROOT\pipeline\01_wiki_fetcher\fetch_full_wiki_extended.py`""                                                                       }
    @{ label = 'Step 2  ─  Deep Evaluation  [LMS]';   exe = $_pwsh; arg = (New-LmsArg $_lmsUrl $_lmsModel $_py "$DD_ROOT\pipeline\02_deep_evaluation\run_evaluation.py")                                              }
    @{ label = 'Step 3  ─  RAG Preprocessing  [LMS]'; exe = $_pwsh; arg = (New-LmsArg $_lmsUrl $_lmsModel $_py "$DD_ROOT\pipeline\03_rag_preprocessing\run_preprocessing.py")                                         }
    @{ label = 'Step 4  ─  Embeddings Creator';       exe = $_py;   arg = "-u `"$DD_ROOT\pipeline\04_embeddings_creator\run_embeddings.py`""                                                                          }
    @{ label = 'Step 5  ─  Deploy';                   exe = $_py;   arg = "-u `"$DD_ROOT\pipeline\05_deploy\run_deploy.py`""                                                                                          }
    @{ label = 'Exit';                                 exe = $null;  arg = $null                                                                                                                                       }
)
$selIdx   = 0
$menuMode = $true    # $true = interactive menu   $false = streaming log
$runLabel = ''       # label of the currently-running step

# ── LOG RING BUFFER ───────────────────────────────────────────────────────────
$logBuf = [System.Collections.Generic.List[string]]::new()

function Add-Line([string]$raw) {
    # Strip ALL ANSI/VT escape sequences so nothing in the stored text can
    # later cause cursor movement when the Render function writes it to the
    # terminal.  Four classes of sequences:
    #   1. CSI  – ESC [ ... final      (\e[0m  \e[2K  \e[?25l  \e[A …)
    #   2. Fe   – ESC followed by one printable char (\e[  \eM  \e7 \e8 …)
    #             IMPORTANT: \eM = "reverse line feed" – moves cursor UP by 1.
    #             Without this strip it accumulates into layout drift / jumping.
    #   3. OSC  – ESC ] ... BEL|ST    (window title, hyperlinks …)
    #   4. DCS/SOS/PM/APC – ESC [P_^X_] ... ST
    # Strip ALL ANSI/VT escape sequences (4 classes – see comments above).
    # Uses separate assignments rather than backtick continuation so that
    # trailing comments never accidentally break the line-continuation rule.
    $plain = $raw  -replace "`e\[[\x20-\x3F]*[\x40-\x7E]",""   # 1. CSI
    $plain = $plain -replace "`e[\x20-\x2F]*[\x40-\x7E]",""     # 2. Fe / 2-char  (\eM !)
    $plain = $plain -replace "`e\][^\a`e]*(`a|`e\\)",""          # 3. OSC
    $plain = $plain -replace "`e[PX\^_][^`e]*`e\\",""            # 4. DCS/APC
    # Truncate plain text to fit, then use that as display (no embedded ANSI from input)
    $maxLen = $PANEL_W - 3
    if ($plain.Length -gt $maxLen) { $plain = $plain.Substring(0, $maxLen) + "…" }
    $raw = $plain   # work with plain text only – colorizer adds ANSI below
    # colorize by keyword
    $col = if     ($raw -match '(?i)error|fail|exception|critical') { $CE  }
           elseif ($raw -match '(?i)\bwarn')                        { $CW  }
           elseif ($raw -match '(?i)\bok\b|success|done|complete')  { $COK }
           else                                                      { $CTX }
    $script:logBuf.Add("$col$raw$RST")
    # keep only what fits
    while ($script:logBuf.Count -gt $PANEL_ROWS) { $script:logBuf.RemoveAt(0) }
}

# ── RENDER FRAME ─────────────────────────────────────────────────────────────
function Render([float]$t) {
    $buf = [System.Text.StringBuilder]::new(($TW + 2) * $BUF_H)
    $null = $buf.Append("$esc[H")

    for ($sr = 0; $sr -lt $BUF_H; $sr++) {
        $null = $buf.Append($BBLK)
        $ar = $sr - $ART_ROW   # row index into logo art

        # ── left margin ──
        $null = $buf.Append(' ' * $ART_COL)

        # ── logo columns ──
        if ($ar -ge 0 -and $ar -lt $ART_H) {
            for ($col = 0; $col -lt $ART_W; $col++) {
                $p  = $PIX[$ar * $ART_W + $col]
                $tr=$p[0];$tg=$p[1];$tb=$p[2];$tv=$p[3]
                $br=$p[4];$bg=$p[5];$bb=$p[6];$bv=$p[7]

                if (-not $tv -and -not $bv) { $null=$buf.Append($BBLK+' '); continue }

                $wx=$col/43.0; $wy=$ar/43.0
                $rx =[Math]::Sin(($wx*3.1+$wy*2.3+$t*0.9) *[Math]::PI*2)
                $ry =[Math]::Sin(($wx*2.7-$wy*3.7+$t*1.1) *[Math]::PI*2)
                $rx2=[Math]::Sin(($wx*1.9+$wy*4.1+$t*0.6) *[Math]::PI*2)
                $ry2=[Math]::Sin(($wx*4.3-$wy*1.8+$t*0.75)*[Math]::PI*2)
                $strength=2.2
                $dx=[int](($rx*0.7+$rx2*0.3)*$strength)
                $dy=[int](($ry*0.7+$ry2*0.3)*$strength)
                $sc=[Math]::Min($ART_W-1,[Math]::Max(0,$col+$dx))
                $srow=[Math]::Min($ART_H-1,[Math]::Max(0,$ar+$dy))
                $ps=$PIX[$srow*$ART_W+$sc]
                $str=$ps[0];$stg=$ps[1];$stb=$ps[2]
                $sbr=$ps[4];$sbg=$ps[5];$sbb=$ps[6]
                $spec=[Math]::Abs($rx-$rx2)*0.5
                $boost=0.85+$spec*0.55

                if ($tv -and $bv) {
                    $fnr=[Math]::Min(255,[Math]::Max(0,[int](($tr*.6+$str*.4)*$boost)))
                    $fng=[Math]::Min(255,[Math]::Max(0,[int](($tg*.6+$stg*.4)*$boost)))
                    $fnb=[Math]::Min(255,[Math]::Max(0,[int](($tb*.6+$stb*.4)*$boost)))
                    $bnr=[Math]::Min(255,[Math]::Max(0,[int](($br*.6+$sbr*.4)*$boost)))
                    $bng=[Math]::Min(255,[Math]::Max(0,[int](($bg*.6+$sbg*.4)*$boost)))
                    $bnb=[Math]::Min(255,[Math]::Max(0,[int](($bb*.6+$sbb*.4)*$boost)))
                    $null=$buf.Append("$esc[38;2;${fnr};${fng};${fnb}m$esc[48;2;${bnr};${bng};${bnb}m`u{2580}")
                } elseif ($tv) {
                    $fnr=[Math]::Min(255,[Math]::Max(0,[int](($tr*.6+$str*.4)*$boost)))
                    $fng=[Math]::Min(255,[Math]::Max(0,[int](($tg*.6+$stg*.4)*$boost)))
                    $fnb=[Math]::Min(255,[Math]::Max(0,[int](($tb*.6+$stb*.4)*$boost)))
                    $null=$buf.Append("$esc[38;2;${fnr};${fng};${fnb}m${BBLK}`u{2580}")
                } else {
                    $bnr=[Math]::Min(255,[Math]::Max(0,[int](($br*.6+$sbr*.4)*$boost)))
                    $bng=[Math]::Min(255,[Math]::Max(0,[int](($bg*.6+$sbg*.4)*$boost)))
                    $bnb=[Math]::Min(255,[Math]::Max(0,[int](($bb*.6+$sbb*.4)*$boost)))
                    $null=$buf.Append("$esc[38;2;${bnr};${bng};${bnb}m${BBLK}`u{2584}")
                }
            }
        } else {
            $null = $buf.Append($BBLK + ' ' * $ART_W)
        }

        # ── gap + divider ──
        $null = $buf.Append($BBLK + '  ')
        if ($sr -eq $ART_ROW) {
            $null = $buf.Append("${CB}╔$('═' * ($PANEL_W + 2))╗$RST$BBLK")
        } elseif ($sr -eq $ART_ROW + 1) {
            $title = if ($menuMode) { " LeoWiki MCP  ─  Pipeline Launcher " } else { " LeoWiki MCP  ─  Live Log " }
            $pad   = [Math]::Max(0, $PANEL_W + 2 - $title.Length)
            $lp    = ' ' * [int]($pad/2); $rp = ' ' * ($pad - [int]($pad/2))
            $null  = $buf.Append("${CB}║${CT}${lp}${title}${rp}${CB}║$RST$BBLK")
        } elseif ($sr -eq $ART_ROW + $ART_H - 2) {
            $now = Get-Date -Format 'HH:mm:ss'
            if ($menuMode) {
                $ts  = " [↑↓] Navigate   [Enter] Run   [Q] Quit   $now "
                $tsc = $CTS
            } elseif ([ProcQ]::Running) {
                $ts  = " [M] Menu   [K] Kill   ► $runLabel   $now "
                $tsc = $CW
            } elseif ([ProcQ]::ExitCode -eq 0) {
                $ts  = " [M] Menu   ✓ done: $runLabel   $now "
                $tsc = $COK
            } else {
                $ec  = [ProcQ]::ExitCode
                if ($null -eq $ec) { $ec = '?' }
                $ts  = " [M] Menu   ✗ failed (exit $ec): $runLabel   $now "
                $tsc = $CE
            }
            $pad   = [Math]::Max(0, $PANEL_W + 2 - $ts.Length)
            $null  = $buf.Append("${CB}║${tsc}$(' '*[int]($pad/2))${ts}$(' '*($pad-[int]($pad/2)))${CB}║$RST$BBLK")
        } elseif ($sr -eq $ART_ROW + $ART_H - 1) {
            $null  = $buf.Append("${CB}╚$('═' * ($PANEL_W + 2))╝$RST$BBLK")
        } elseif ($sr -ge $PANEL_TOP -and $sr -lt ($PANEL_TOP + $PANEL_ROWS)) {
            $li   = $sr - $PANEL_TOP
            $line = $null
            if ($menuMode) {
                # ── MENU ──
                $mStart = 3
                if ($li -eq 1) {
                    $line = "${CT}── Select a Pipeline Step ──${RST}"
                } elseif ($li -ge $mStart -and $li -lt ($mStart + $menuItems.Count)) {
                    $i    = $li - $mStart
                    $item = $menuItems[$i]
                    $line = if ($i -eq $selIdx) { "${COK}▶  $($item.label)${RST}" } `
                            else                { "${CTX}   $($item.label)${RST}" }
                }
            } else {
                # ── LOG ──
                if ($li -lt $logBuf.Count) { $line = $logBuf[$li] }
            }
            if ($null -ne $line) {
                # Broad ANSI strip for accurate display-width measurement
                $plain  = $line -replace "`e\[[\d;?]*[A-Za-z]","" `
                                -replace "`e\][^\a]*(`a|`e\\)",""
                # Safety clamp: if a line somehow escaped Add-Line's truncation
                # (e.g. a menu label that's very long) clamp it here so the
                # panel box never wraps the terminal line and causes layout jumps.
                if ($plain.Length -gt $PANEL_W - 1) {
                    $line  = $plain.Substring(0, $PANEL_W - 1) + "…"
                    $plain = $line
                }
                $padLen = [Math]::Max(0, $PANEL_W - $plain.Length)
                $null   = $buf.Append("${CB}║$RST ${line}$(' '*$padLen) ${CB}║$RST$BBLK")
            } else {
                $null = $buf.Append("${CB}║${CD}$('·' * ($PANEL_W + 2))${CB}║$RST$BBLK")
            }
        } else {
            # rows outside box area
            $gap = $TW - $ART_COL - $ART_W - 2
            $null = $buf.Append($BBLK + ' ' * [Math]::Max(0,$gap))
        }

        $null = $buf.Append($RST)
        if ($sr -lt $BUF_H - 1) { $null = $buf.Append("`n") }
    }

    [Console]::Write($buf.ToString())
}

# ── MAIN LOOP ─────────────────────────────────────────────────────────────────
# Switch to the ALTERNATE SCREEN BUFFER.  This is the definitive fix for the
# "jumping / layout drift" problem.  The alt screen:
#   • is completely isolated from the normal scroll-back buffer
#   • never scrolls (no line can drift the cursor out of position)
#   • is restored automatically on exit so the user's normal terminal is intact
[Console]::Write("$esc[?1049h$esc[2J$esc[H")
$t          = 0.0
$wasRunning = $false

# Suppress echo of typed chars bleeding onto screen
$origMode = $null
try {
    Add-Type -Name WinCon -Namespace '' -MemberDefinition @"
        [DllImport("kernel32.dll")] public static extern bool GetConsoleMode(IntPtr h, out uint m);
        [DllImport("kernel32.dll")] public static extern bool SetConsoleMode(IntPtr h, uint m);
        [DllImport("kernel32.dll")] public static extern IntPtr GetStdHandle(int n);
"@
    $hIn = [WinCon]::GetStdHandle(-10)
    $mode = 0
    [WinCon]::GetConsoleMode($hIn, [ref]$mode) | Out-Null
    $origMode = $mode
    # Clear ENABLE_ECHO_INPUT (0x0004) and ENABLE_LINE_INPUT (0x0002)
    [WinCon]::SetConsoleMode($hIn, $mode -band (-bnot 0x0006)) | Out-Null
} catch {}

$running = $true
# Ctrl+C stops the TUI loop without killing the host.
# Cursor/VS Code integrated terminals often lack CancelKeyPress — Q still quits.
try {
    [Console]::add_CancelKeyPress({
        param($s, $e)
        $e.Cancel = $true
        $script:running = $false
    })
} catch {
    # Host has no CancelKeyPress event; ignore.
}

while ($running) {
    # ── Drain process output ──────────────────────────────────────────────────
    if (-not $menuMode) {
        $ln = $null
        while ([ProcQ]::Lines.TryDequeue([ref]$ln)) { Add-Line $ln }
        # Detect process completion and add a visual separator (respect exit code)
        $nowRunning = [ProcQ]::Running
        if ($wasRunning -and -not $nowRunning) {
            if ([ProcQ]::ExitCode -eq 0) {
                Add-Line "── done: $runLabel ──"
            } else {
                $ec = [ProcQ]::ExitCode
                if ($null -eq $ec) { $ec = '?' }
                Add-Line "── failed (exit $ec): $runLabel ──"
            }
        }
        $wasRunning = $nowRunning
    }

    # ── Keyboard input ────────────────────────────────────────────────────────
    while ([Console]::KeyAvailable) {
        $key = [Console]::ReadKey($true)
        $k   = $key.Key
        $c   = $key.KeyChar

        if ($menuMode) {
            if     ($k -eq [ConsoleKey]::UpArrow)   { if ($selIdx -gt 0)                    { $selIdx-- } }
            elseif ($k -eq [ConsoleKey]::DownArrow) { if ($selIdx -lt $menuItems.Count - 1) { $selIdx++ } }
            elseif ($k -eq [ConsoleKey]::Enter) {
                $item = $menuItems[$selIdx]
                if ($null -eq $item.exe) {
                    $running = $false
                } else {
                    $logBuf.Clear()
                    $runLabel   = $item.label
                    $menuMode   = $false
                    $wasRunning = $true
                    [ProcQ]::StartProcess($item.exe, $item.arg, $DD_ROOT)
                }
            }
            elseif ($c -eq 'q' -or $c -eq 'Q') { $running = $false }
        } else {
            if     ($c -eq 'm' -or $c -eq 'M') { $menuMode = $true }
            elseif ($c -eq 'k' -or $c -eq 'K') {
                [ProcQ]::Kill()
                Add-Line "[KILLED] Process stopped by user."
                $wasRunning = $false
            }
            elseif ($c -eq 'q' -or $c -eq 'Q') { [ProcQ]::Kill(); $running = $false }
        }
    }

    $t += 0.018
    Render $t
    Start-Sleep -Milliseconds 33
}

# Restore console mode
try {
    if ($null -ne $origMode) {
        [WinCon]::SetConsoleMode([WinCon]::GetStdHandle(-10), $origMode) | Out-Null
    }
} catch {}

# Restore the normal screen buffer (undoes \e[?1049h)
[Console]::Write("$esc[?1049l")
[console]::CursorVisible = $true
